#[doc = "Online compiler and linker options"]
#[derive(Debug, Copy, Clone, Hash, PartialEq, Eq)]
pub enum CUjit_option_enum {
    #[doc = "Max number of registers that a thread may use.\\n Option type: unsigned int\\n Applies to: compiler only"]
    CU_JIT_MAX_REGISTERS = 0,
    #[doc = "IN: Specifies minimum number of threads per block to target compilation\nfor\\n OUT: Returns the number of threads the compiler actually targeted.\nThis restricts the resource utilization of the compiler (e.g. max\nregisters) such that a block with the given number of threads should be\nable to launch based on register limitations. Note, this option does not\ncurrently take into account any other resource limitations, such as\nshared memory utilization.\\n Cannot be combined with ::CU_JIT_TARGET.\\n Option type: unsigned int\\n Applies to: compiler only"]
    CU_JIT_THREADS_PER_BLOCK = 1,
    #[doc = "Overwrites the option value with the total wall clock time, in\nmilliseconds, spent in the compiler and linker\\n Option type: float\\n Applies to: compiler and linker"]
    CU_JIT_WALL_TIME = 2,
    #[doc = "Pointer to a buffer in which to print any log messages\nthat are informational in nature (the buffer size is specified via\noption ::CU_JIT_INFO_LOG_BUFFER_SIZE_BYTES)\\n Option type: char *\\n Applies to: compiler and linker"]
    CU_JIT_INFO_LOG_BUFFER = 3,
    #[doc = "IN: Log buffer size in bytes.  Log messages will be capped at this size\n(including null terminator)\\n OUT: Amount of log buffer filled with messages\\n Option type: unsigned int\\n Applies to: compiler and linker"]
    CU_JIT_INFO_LOG_BUFFER_SIZE_BYTES = 4,
    #[doc = "Pointer to a buffer in which to print any log messages that\nreflect errors (the buffer size is specified via option\n::CU_JIT_ERROR_LOG_BUFFER_SIZE_BYTES)\\n Option type: char *\\n Applies to: compiler and linker"]
    CU_JIT_ERROR_LOG_BUFFER = 5,
    #[doc = "IN: Log buffer size in bytes.  Log messages will be capped at this size\n(including null terminator)\\n OUT: Amount of log buffer filled with messages\\n Option type: unsigned int\\n Applies to: compiler and linker"]
    CU_JIT_ERROR_LOG_BUFFER_SIZE_BYTES = 6,
    #[doc = "Level of optimizations to apply to generated code (0 - 4), with 4\nbeing the default and highest level of optimizations.\\n Option type: unsigned int\\n Applies to: compiler only"]
    CU_JIT_OPTIMIZATION_LEVEL = 7,
    #[doc = "No option value required. Determines the target based on the current\nattached context (default)\\n Option type: No option value needed\\n Applies to: compiler and linker"]
    CU_JIT_TARGET_FROM_CUCONTEXT = 8,
    #[doc = "Target is chosen based on supplied ::CUjit_target.  Cannot be\ncombined with ::CU_JIT_THREADS_PER_BLOCK.\\n Option type: unsigned int for enumerated type ::CUjit_target\\n Applies to: compiler and linker"]
    CU_JIT_TARGET = 9,
    #[doc = "Specifies choice of fallback strategy if matching cubin is not found.\nChoice is based on supplied ::CUjit_fallback.  This option cannot be\nused with cuLink* APIs as the linker requires exact matches.\\n Option type: unsigned int for enumerated type ::CUjit_fallback\\n Applies to: compiler only"]
    CU_JIT_FALLBACK_STRATEGY = 10,
    #[doc = "Specifies whether to create debug information in output (-g)\n(0: false, default)\\n Option type: int\\n Applies to: compiler and linker"]
    CU_JIT_GENERATE_DEBUG_INFO = 11,
    #[doc = "Generate verbose log messages (0: false, default)\\n Option type: int\\n Applies to: compiler and linker"]
    CU_JIT_LOG_VERBOSE = 12,
    #[doc = "Generate line number information (-lineinfo) (0: false, default)\\n Option type: int\\n Applies to: compiler only"]
    CU_JIT_GENERATE_LINE_INFO = 13,
    #[doc = "Specifies whether to enable caching explicitly (-dlcm) \\n Choice is based on supplied ::CUjit_cacheMode_enum.\\n Option type: unsigned int for enumerated type ::CUjit_cacheMode_enum\\n Applies to: compiler only"]
    CU_JIT_CACHE_MODE = 14,
    #[doc = "> **Deprecated** This jit option is deprecated and should not be used."]
    CU_JIT_NEW_SM3X_OPT = 15,
    #[doc = "This jit option is used for internal purpose only."]
    CU_JIT_FAST_COMPILE = 16,
    #[doc = "Array of device symbol names that will be relocated to the corresponding\nhost addresses stored in ::CU_JIT_GLOBAL_SYMBOL_ADDRESSES.\\n Must contain ::CU_JIT_GLOBAL_SYMBOL_COUNT entries.\\n When loading a device module, driver will relocate all encountered\nunresolved symbols to the host addresses.\\n It is only allowed to register symbols that correspond to unresolved\nglobal variables.\\n It is illegal to register the same device symbol at multiple addresses.\\n Option type: const char **\\n Applies to: dynamic linker only"]
    CU_JIT_GLOBAL_SYMBOL_NAMES = 17,
    #[doc = "Array of host addresses that will be used to relocate corresponding\ndevice symbols stored in ::CU_JIT_GLOBAL_SYMBOL_NAMES.\\n Must contain ::CU_JIT_GLOBAL_SYMBOL_COUNT entries.\\n Option type: void **\\n Applies to: dynamic linker only"]
    CU_JIT_GLOBAL_SYMBOL_ADDRESSES = 18,
    #[doc = "Number of entries in ::CU_JIT_GLOBAL_SYMBOL_NAMES and\n::CU_JIT_GLOBAL_SYMBOL_ADDRESSES arrays.\\n Option type: unsigned int\\n Applies to: dynamic linker only"]
    CU_JIT_GLOBAL_SYMBOL_COUNT = 19,
    #[doc = "> **Deprecated** Enable link-time optimization (-dlto) for device code (Disabled by default).\\n This option is not supported on 32-bit platforms.\\n Option type: int\\n Applies to: compiler and linker\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_LTO = 20,
    #[doc = "> **Deprecated** Control single-precision denormals (-ftz) support (0: false, default).\n1 : flushes denormal values to zero\n0 : preserves denormal values\nOption type: int\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_FTZ = 21,
    #[doc = "> **Deprecated** Control single-precision floating-point division and reciprocals\n(-prec-div) support (1: true, default).\n1 : Enables the IEEE round-to-nearest mode\n0 : Enables the fast approximation mode\nOption type: int\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_PREC_DIV = 22,
    #[doc = "> **Deprecated** Control single-precision floating-point square root\n(-prec-sqrt) support (1: true, default).\n1 : Enables the IEEE round-to-nearest mode\n0 : Enables the fast approximation mode\nOption type: int\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_PREC_SQRT = 23,
    #[doc = "> **Deprecated** Enable/Disable the contraction of floating-point multiplies\nand adds/subtracts into floating-point multiply-add (-fma)\noperations (1: Enable, default; 0: Disable).\nOption type: int\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_FMA = 24,
    #[doc = "> **Deprecated** Array of kernel names that should be preserved at link time while others\ncan be removed.\\n Must contain ::CU_JIT_REFERENCED_KERNEL_COUNT entries.\\n Note that kernel names can be mangled by the compiler in which case the\nmangled name needs to be specified.\\n Wildcard \"*\" can be used to represent zero or more characters instead of\nspecifying the full or mangled name.\\n It is important to note that the wildcard \"*\" is also added implicitly.\nFor example, specifying \"foo\" will match \"foobaz\", \"barfoo\", \"barfoobaz\" and\nthus preserve all kernels with those names. This can be avoided by providing\na more specific name like \"barfoobaz\".\\n Option type: const char **\\n Applies to: dynamic linker only\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_REFERENCED_KERNEL_NAMES = 25,
    #[doc = "> **Deprecated** Number of entries in ::CU_JIT_REFERENCED_KERNEL_NAMES array.\\n Option type: unsigned int\\n Applies to: dynamic linker only\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_REFERENCED_KERNEL_COUNT = 26,
    #[doc = "> **Deprecated** Array of variable names (__device__ and/or __constant__) that should be\npreserved at link time while others can be removed.\\n Must contain ::CU_JIT_REFERENCED_VARIABLE_COUNT entries.\\n Note that variable names can be mangled by the compiler in which case the\nmangled name needs to be specified.\\n Wildcard \"*\" can be used to represent zero or more characters instead of\nspecifying the full or mangled name.\\n It is important to note that the wildcard \"*\" is also added implicitly.\nFor example, specifying \"foo\" will match \"foobaz\", \"barfoo\", \"barfoobaz\" and\nthus preserve all variables with those names. This can be avoided by providing\na more specific name like \"barfoobaz\".\\n Option type: const char **\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_REFERENCED_VARIABLE_NAMES = 27,
    #[doc = "> **Deprecated** Number of entries in ::CU_JIT_REFERENCED_VARIABLE_NAMES array.\\n Option type: unsigned int\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_REFERENCED_VARIABLE_COUNT = 28,
    #[doc = "> **Deprecated** This option serves as a hint to enable the JIT compiler/linker\nto remove constant (__constant__) and device (__device__) variables\nunreferenced in device code (Disabled by default).\\n Note that host references to constant and device variables using APIs like\n::cuModuleGetGlobal() with this option specified may result in undefined behavior unless\nthe variables are explicitly specified using ::CU_JIT_REFERENCED_VARIABLE_NAMES.\\n Option type: int\\n Applies to: link-time optimization specified with CU_JIT_LTO\nOnly valid with LTO-IR compiled with toolkits prior to CUDA 12.0"]
    CU_JIT_OPTIMIZE_UNUSED_DEVICE_VARIABLES = 29,
    #[doc = "Generate position independent code (0: false)\\n Option type: int\\n Applies to: compiler only"]
    CU_JIT_POSITION_INDEPENDENT_CODE = 30,
    #[doc = "This option hints to the JIT compiler the minimum number of CTAs from the\nkernel’s grid to be mapped to a SM. This option is ignored when used together\nwith ::CU_JIT_MAX_REGISTERS or ::CU_JIT_THREADS_PER_BLOCK.\nOptimizations based on this option need ::CU_JIT_MAX_THREADS_PER_BLOCK to\nbe specified as well. For kernels already using PTX directive .minnctapersm,\nthis option will be ignored by default. Use ::CU_JIT_OVERRIDE_DIRECTIVE_VALUES\nto let this option take precedence over the PTX directive.\nOption type: unsigned int\\n Applies to: compiler only"]
    CU_JIT_MIN_CTA_PER_SM = 31,
    #[doc = "Maximum number threads in a thread block, computed as the product of\nthe maximum extent specifed for each dimension of the block. This limit\nis guaranteed not to be exeeded in any invocation of the kernel. Exceeding\nthe the maximum number of threads results in runtime error or kernel launch\nfailure. For kernels already using PTX directive .maxntid, this option will\nbe ignored by default. Use ::CU_JIT_OVERRIDE_DIRECTIVE_VALUES to let this\noption take precedence over the PTX directive.\nOption type: int\\n Applies to: compiler only"]
    CU_JIT_MAX_THREADS_PER_BLOCK = 32,
    #[doc = "This option lets the values specified using ::CU_JIT_MAX_REGISTERS,\n::CU_JIT_THREADS_PER_BLOCK, ::CU_JIT_MAX_THREADS_PER_BLOCK and\n::CU_JIT_MIN_CTA_PER_SM take precedence over any PTX directives.\n(0: Disable, default; 1: Enable)\nOption type: int\\n Applies to: compiler only"]
    CU_JIT_OVERRIDE_DIRECTIVE_VALUES = 33,
    #[doc = "This option specifies the maximum number of concurrent threads to use\nwhen running compiler optimizations. If the specified value is 1, the\noption will be ignored. If the specified value is 0, the number of\nthreads will match the number of CPUs on the underlying machine.\nOtherwise, if the option is N, then up to N threads will be used.\nOption type: unsigned int\\n Applies to: compiler only"]
    CU_JIT_SPLIT_COMPILE = 34,
    #[doc = "This option specifies the maximum number of concurrent threads to use\nwhen compiling device code. If the specified value is 1, the option will\nbe ignored. If the specified value is 0, the number of threads will match\nthe number of CPUs on the underlying machine. Otherwise, if the option is\nN, then up to N threads will be used.\nThis option is ignored if the env var CUDA_BINARY_LOADER_THREAD_COUNT is set.\nOption type: unsigned int\\n Applies to: compiler and linker"]
    CU_JIT_BINARY_LOADER_THREAD_COUNT = 35,
    #[doc = "This option specifies the maximum number of concurrent threads to use\nwhen compiling device code. If the specified value is 1, the option will\nbe ignored. If the specified value is 0, the number of threads will match\nthe number of CPUs on the underlying machine. Otherwise, if the option is\nN, then up to N threads will be used.\nThis option is ignored if the env var CUDA_BINARY_LOADER_THREAD_COUNT is set.\nOption type: unsigned int\\n Applies to: compiler and linker"]
    CU_JIT_NUM_OPTIONS = 36,
}
